import React, { useState, useRef, useEffect } from 'react';
import ResumePopup from './components/ResumePopup'; // Import the new component

// Define the shape of a chat message
interface ChatMessage {
  role: 'user' | 'model';
  parts: { text: string }[];
}

export default function Home() {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState<string>('');
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [showResumePopup, setShowResumePopup] = useState<boolean>(false); // New state for popup
  const messagesEndRef = useRef<HTMLDivElement>(null); // Ref for auto-scrolling

  // Function to scroll to the bottom of the chat
  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  // Scroll to bottom whenever messages change
  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  // Handle sending a message
  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMessage: ChatMessage = { role: 'user', parts: [{ text: input.trim() }] };

    // Optimistically update messages with the user's message
    const updatedMessages = [...messages, userMessage];
    setMessages(updatedMessages);
    setInput('');
    setIsLoading(true);
    setShowResumePopup(false); // Close popup if it was open on new message

    try {
      const response = await fetch('/api/chat', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          history: messages, // Send previous messages for context
          prompt: userMessage.parts[0].text, // Send the new user prompt
        }),
      });

      if (!response.ok) {
        const errorData = await response.json();
        console.error('API Error:', errorData);
        setMessages((prevMessages) => [
          ...prevMessages,
          { role: 'model', parts: [{ text: `Error: ${errorData.detail || errorData.error || 'Could not get a response.'}` }] },
        ]);
        return;
      }

      const data = await response.json();
      const botMessage: ChatMessage = { role: 'model', parts: [{ text: data.response }] };
      setMessages((prevMessages) => [...prevMessages, botMessage]);

      // --- NEW: Check for UI action signal from backend ---
      if (data.ui_action === 'show_resume_popup') {
        setShowResumePopup(true);
      }

    } catch (error) {
      console.error('Fetch error:', error);
      setMessages((prevMessages) => [
        ...prevMessages,
        { role: 'model', parts: [{ text: 'An unexpected error occurred. Please try again.' }] },
      ]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-screen max-h-screen items-center justify-center p-4 font-inter">
      <div className="flex flex-col w-full max-w-2xl h-full bg-card rounded-lg shadow-lg overflow-hidden">
        {/* Chat Header */}
        <div className="p-4 bg-primary text-white text-xl font-bold rounded-t-lg">
          Web Dev Chatbot
        </div>

        {/* Chat Messages Area */}
        <div className="flex-1 p-4 overflow-y-auto space-y-4">
          {messages.length === 0 && (
            <div className="text-center text-gray-400 mt-10">
              Type a message to start chatting!
            </div>
          )}
          {messages.map((msg, index) => (
            <div
              key={index}
              className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
            >
              <div
                className={`max-w-[75%] p-3 rounded-lg shadow-md ${
                  msg.role === 'user'
                    ? 'bg-secondary text-white rounded-br-none'
                    : 'bg-gray-700 text-text rounded-bl-none'
                }`}
              >
                {msg.parts.map((part, partIndex) => (
                  <p key={partIndex}>{part.text}</p>
                ))}
              </div>
            </div>
          ))}
          {isLoading && (
            <div className="flex justify-start">
              <div className="max-w-[75%] p-3 rounded-lg shadow-md bg-gray-700 text-text rounded-bl-none">
                <div className="flex items-center space-x-2">
                  <div className="w-2 h-2 bg-text rounded-full animate-bounce" style={{ animationDelay: '0s' }}></div>
                  <div className="w-2 h-2 bg-text rounded-full animate-bounce" style={{ animationDelay: '0.2s' }}></div>
                  <div className="w-2 h-2 bg-text rounded-full animate-bounce" style={{ animationDelay: '0.4s' }}></div>
                </div>
              </div>
            </div>
          )}
          <div ref={messagesEndRef} /> {/* Element to scroll to */}
        </div>

        {/* Chat Input Area */}
        <form onSubmit={handleSendMessage} className="p-4 border-t border-gray-600 flex gap-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Type your message..."
            className="flex-1 p-3 rounded-lg bg-gray-700 text-text border border-gray-600 focus:outline-none focus:border-primary"
            disabled={isLoading}
          />
          <button
            type="submit"
            className="px-6 py-3 bg-primary text-white font-semibold rounded-lg shadow-md hover:bg-secondary transition-colors duration-200 disabled:opacity-50 disabled:cursor-not-allowed"
            disabled={isLoading}
          >
            Send
          </button>
        </form>
      </div>

      {/* Resume Popup Component */}
      <ResumePopup isOpen={showResumePopup} onClose={() => setShowResumePopup(false)} />
    </div>
  );
}
