const GEMINI_API_KEY = process.env.GEMINI_API_KEY || '';

// Define your custom instructions for the chatbot.
// These will "prime" the model with its role and behavior.
const CUSTOM_INSTRUCTIONS = [
  { role: "user", parts: [{ text: "You are a highly knowledgeable and friendly AI assistant specializing in web development, particularly Next.js, React, TypeScript, and Tailwind CSS. Provide concise, accurate, and helpful answers. Always maintain a positive and encouraging tone. If a question is outside your expertise, politely state so." }] },
  { role: "model", parts: [{ text: "Hello! I'm ready to assist you with all your web development queries. How can I help you today?" }] },
];

export async function POST(req: NextRequest) {
  try {
    // Parse the request body, which should contain the chat history
    const { history } = await req.json();

    if (!history || !Array.isArray(history)) {
      return NextResponse.json({ error: 'Invalid chat history provided.' }, { status: 400 });
    }

    // Combine custom instructions with the incoming chat history
    const chatHistory = [...CUSTOM_INSTRUCTIONS, ...history];

    const payload = {
      contents: chatHistory,
      generationConfig: {
        // You can adjust these parameters for different model behaviors
        temperature: 0.7,
        topK: 40,
        topP: 0.95,
      },
    };

    const apiUrl = `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=${GEMINI_API_KEY}`;

    const response = await fetch(apiUrl, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(payload),
    });

    if (!response.ok) {
      const errorData = await response.json();
      console.error('Gemini API error:', errorData);
      return NextResponse.json({ error: 'Failed to get response from Gemini API.', details: errorData }, { status: response.status });
    }

    const result = await response.json();

    if (result.candidates && result.candidates.length > 0 &&
        result.candidates[0].content && result.candidates[0].content.parts &&
        result.candidates[0].content.parts.length > 0) {
      const text = result.candidates[0].content.parts[0].text;
      return NextResponse.json({ response: text });
    } else {
      console.warn('Gemini API response structure unexpected:', result);
      return NextResponse.json({ error: 'Unexpected response from Gemini API.' }, { status: 500 });
    }

  } catch (error) {
    console.error('API Route error:', error);
    return NextResponse.json({ error: 'Internal server error.' }, { status: 500 });
  }
}
